import{c as t,Q as i,j as r,m as l}from"./chunks/framework.BXc4yaFE.js";const h=JSON.parse('{"title":"Designing, Refining, and Maintaining Agent Skills at Perplexity","description":"","frontmatter":{"url":"https://research.perplexity.ai/articles/designing-refining-and-maintaining-agent-skills-at-perplexity","date":"2026-05-10T00:00:00.000Z","scored":"2026-05-16T00:00:00.000Z","source":"Perplexity Research Blog","source_file":"../2026-05-10-designing-refining-and-maintaining-agent-skills-at-perplexity.md","source_tier":"C","tags":["skill-design","progressive-loading","skill-index","gotchas-flywheel","eval-first"]},"headers":[],"relativePath":"research/ai-articles/scored/2026-05-10-designing-refining-and-maintaining-agent-skills-at-perplexity.md","filePath":"research/ai-articles/scored/2026-05-10-designing-refining-and-maintaining-agent-skills-at-perplexity.md","lastUpdated":1779894392000}'),n={name:"research/ai-articles/scored/2026-05-10-designing-refining-and-maintaining-agent-skills-at-perplexity.md"};function a(d,e,s,o,g,c){return i(),r("div",null,[...e[0]||(e[0]=[l('<h1 id="designing-refining-and-maintaining-agent-skills-at-perplexity" tabindex="-1">Designing, Refining, and Maintaining Agent Skills at Perplexity <a class="header-anchor" href="#designing-refining-and-maintaining-agent-skills-at-perplexity" aria-label="Permalink to &quot;Designing, Refining, and Maintaining Agent Skills at Perplexity&quot;">​</a></h1><p><strong>原始來源</strong>：<a href="https://research.perplexity.ai/articles/designing-refining-and-maintaining-agent-skills-at-perplexity" target="_blank" rel="noreferrer">https://research.perplexity.ai/articles/designing-refining-and-maintaining-agent-skills-at-perplexity</a><br><strong>字數</strong>：約 3,948 字</p><hr><h2 id="tl-dr" tabindex="-1">TL;DR <a class="header-anchor" href="#tl-dr" aria-label="Permalink to &quot;TL;DR&quot;">​</a></h2><p>Perplexity 內部 Skill 設計指南。核心論點：「Skill 設計哲學與寫 code 完全相反」——好的 code 準則（Simple、Explicit、Sparse）在 Skill 中往往是反模式。三層 Progressive Loading 架構（Index 100t / Load 5k / Runtime 無上限）、eval-first 流程、gotchas flywheel，是生產品質 Skill 的核心。</p><hr><h2 id="核心主張" tabindex="-1">核心主張 <a class="header-anchor" href="#核心主張" aria-label="Permalink to &quot;核心主張&quot;">​</a></h2><ol><li><p><strong>Skill 是 Directory，不是 File</strong></p><ul><li>Hub（<code>SKILL.md</code>）+ Spokes（<code>scripts/</code>、<code>references/</code>、<code>assets/</code>、<code>config.json</code>）</li><li>多層 hierarchy 解決大規模知識路由：1,945 節稅法 → 20 類 × 15 條 &gt; 單平鋪</li></ul></li><li><p><strong>三層 Progressive Loading Token 預算</strong></p><table tabindex="0"><thead><tr><th>Tier</th><th>載入內容</th><th>Token 預算</th><th>何時付費</th></tr></thead><tbody><tr><td>Index</td><td>name + description</td><td>~100t/Skill</td><td>每 session 必付</td></tr><tr><td>Load</td><td>完整 SKILL.md body</td><td>~5,000t</td><td>呼叫後到 compaction</td></tr><tr><td>Runtime</td><td>scripts/references/assets</td><td>無上限</td><td>需要時才讀</td></tr></tbody></table></li><li><p><strong>Description 是 Routing Trigger，不是文件</strong></p><ul><li>格式：「Load when...」（≤50 字）</li><li>錯誤：描述 Skill 功能。正確：描述用戶意圖（real queries）</li><li>描述改動需重跑 eval，否則不改</li></ul></li><li><p><strong>Gotchas 是最高密度內容</strong></p><ul><li>Agent 失敗 → append gotcha（負例）</li><li>off-target load → 收緊 description + 加負例 eval</li><li>Skill 是 append-mostly，description 改動才是例外</li></ul></li><li><p><strong>arxiv 實證：LLM 無法自行寫好 Skill</strong></p><ul><li>論文 <a href="https://arxiv.org/abs/2602.12670" target="_blank" rel="noreferrer">2602.12670</a>：Self-generated Skills 平均無益</li><li>結論：Skill 必須注入人類判斷與領域知識</li></ul></li></ol><hr><h2 id="cc-workspace-可行動性" tabindex="-1">cc-workspace 可行動性 <a class="header-anchor" href="#cc-workspace-可行動性" aria-label="Permalink to &quot;cc-workspace 可行動性&quot;">​</a></h2><ol><li><p><strong>Skill Index token 預算提醒</strong>：每個 Skill 的 description ≤100 tokens，因為所有 session 都付費。當前 .claude/skills/ 下的 Skill description 是否過長？</p></li><li><p><strong>Reference 抽離原則</strong>：條件性重內容（API 文件、特殊情況）應移至 <code>references/</code> 按需載入，不要塞進主 SKILL.md body。</p></li><li><p><strong>Eval-before-description</strong>：新 Skill 先寫 eval case（包含負例），再寫 description；description 改動後重跑 eval。</p></li><li><p><strong>描述格式標準化</strong>：統一 <code>Load when...</code> 格式；cc-workspace 現有 Skill 可審查是否符合。</p></li></ol><hr><h2 id="評分" tabindex="-1">評分 <a class="header-anchor" href="#評分" aria-label="Permalink to &quot;評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>理由</th></tr></thead><tbody><tr><td>A. Workspace 可行動性</td><td>9/10</td><td>3-tier token budget、gotchas flywheel、directory structure 直接可套用至 cc-workspace Skill 設計審查</td></tr><tr><td>B. 創新性</td><td>8/10</td><td>「Zen of Python vs Zen of Skills」對比新穎；LLM 無法自寫 Skill 的 arxiv 實證未見於現有 rules</td></tr><tr><td>C. 證據品質</td><td>7/10</td><td>引用 arxiv 論文 + Perplexity 生產案例（稅法 1945 節）；缺量化 eval 數據</td></tr><tr><td>D. 技術深度</td><td>9/10</td><td>具體 token budget 數字、目錄結構、5步驟建設流程、eval suite 分類（load precision/recall、progressive read、end-to-end）</td></tr><tr><td>E. 泛化性</td><td>9/10</td><td>原則適用任何 skill-based agent 系統，非 Perplexity 專屬</td></tr><tr><td><strong>加權總分</strong></td><td><strong>8.4/10</strong></td><td>9×0.3 + 8×0.2 + 7×0.2 + 9×0.15 + 9×0.15 = 2.70+1.60+1.40+1.35+1.35</td></tr></tbody></table><p><strong>整合決策</strong>：Rule（通用原則適用所有 Skill 設計任務）<br><strong>整合位置</strong>：<code>.claude/refs/skill-design-guide.md</code>（新建）或補充進 <code>.claude/rules/core.md</code> § Skill 設計原則<br><strong>整合狀態</strong>：待實作</p><hr><h2 id="todo" tabindex="-1">TODO <a class="header-anchor" href="#todo" aria-label="Permalink to &quot;TODO&quot;">​</a></h2><ul><li>[ ] 新建 <code>.claude/refs/skill-design-guide.md</code>，收錄：3-tier token budget、description 格式規範（Load when...）、gotchas flywheel、eval-first checklist</li><li>[ ] 審查現有 <code>.claude/skills/*/SKILL.md</code> 的 description 是否符合 ≤50 字 / Load when... 格式</li><li>[ ] 確認 references/ 抽離原則已反映在 skill-authoring-patterns</li></ul>',18)])])}const k=t(n,[["render",a]]);export{h as __pageData,k as default};
